def find_review_object(value: Any) -> dict[str, Any] | None:
    """Find a cloud-review object in CLI JSON envelopes without assuming one vendor shape."""
    if isinstance(value, dict):
        if value.get("status") in {"pass", "fail", "needs_review"} and isinstance(value.get("summary"), str):
            return value
        for candidate in value.values():
            found = find_review_object(candidate)
            if found is not None:
                return found
    elif isinstance(value, list):
        for candidate in value:
            found = find_review_object(candidate)
            if found is not None:
                return found
    elif isinstance(value, str):
        try:
            parsed = extract_json_object(value)
        except HubError:
            return None
        return find_review_object(parsed)
    return None


